import { Injectable, NgZone, inject } from '@angular/core';
import {
  ActivatedRouteSnapshot,
  RouterStateSnapshot,
  UrlTree,
  Route,
  UrlSegment,
} from '@angular/router';
import { Observable } from 'rxjs';
import { AuthService } from '../services/auth.service';

import { NavController } from '@ionic/angular/standalone';
import { AlertService } from '@trokai/shared-ui';

@Injectable({
  providedIn: 'root',
})
export class AuthGuard {
  private ngZone = inject(NgZone);
  private authService = inject(AuthService);
  private navCtrl = inject(NavController);
  private alertSerivce = inject(AlertService);

  canActivate(
    route: ActivatedRouteSnapshot,
    state: RouterStateSnapshot
  ):
    | boolean
    | UrlTree
    | Observable<boolean | UrlTree>
    | Promise<boolean | UrlTree> {
    const allows = !!this.authService.getUserValue();

    if (!allows) this.authService.askToLogin();

    return allows;
  }

  // canLoad ao inves de canActivate para evitar que o lazy loaded baixe a pagina que nao poderei acessar
  canLoad(
    route: Route,
    segments: UrlSegment[]
  ): Observable<boolean> | Promise<boolean> | boolean {
    const allows = !!this.authService.getUserValue();

    if (!allows) this.authService.askToLogin();

    return allows;
  }
}

import { Component, OnDestroy, AfterViewInit, inject, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../services/auth.service';
import { Subscription } from 'rxjs';
import { Browser } from '@capacitor/browser';
import { LoginPage } from './login/login.page';

import {
  SignInWithApple,
  SignInWithAppleResponse,
  SignInWithAppleOptions,
} from '@capacitor-community/apple-sign-in';

import {
  IonButton,
  IonContent,
  IonGrid,
  IonIcon,
  IonImg,
  IonNav,
  isPlatform,
  LoadingController,
  IonLabel,
  IonText,
  IonRow,
  IonSpinner,
} from '@ionic/angular/standalone';
// const { SignInWithApple } = Plugins;
import { logoApple } from 'ionicons/icons';
import { addIcons } from 'ionicons';
import { AlertService } from '@trokai/shared-ui';
import { FirebaseService } from '../services/firebase.service';
import { ToastService } from '../services/toast-service';
import { MainService } from '../services/main.service';
import { environment } from 'src/environments/environment';
import { SocialLogin } from '@capgo/capacitor-social-login';
@Component({
  selector: 'app-auth',
  templateUrl: './auth.page.html',
  styleUrls: ['./auth.page.scss'],
  standalone: true,
  imports: [
    IonSpinner,
    IonRow,
    IonText,
    IonLabel,
    IonContent,
    IonGrid,
    IonIcon,
    IonButton,
    IonImg,
  ],
})
export class AuthPage implements OnDestroy, AfterViewInit, OnInit {
  private router = inject(Router);
  private loadingCtrl = inject(LoadingController);
  private authService = inject(AuthService);
  private toastService = inject(ToastService);
  private ionNav = inject(IonNav);
  private firebaseService = inject(FirebaseService);
  private mainService = inject(MainService);
  private alert = inject(AlertService);

  // user: Observable<firebase.default.User>;
  user;
  authSub: Subscription;
  hasAuth = false;
  loading = false;
  showPhone = false;
  showApple = false;

  ngOnInit() {
    addIcons({ logoApple });
  }


  ngAfterViewInit() {
    if (isPlatform('ios')) this.showApple = true;
  }

  async openPoliticas() {
    this.mainService.openTrokaiWebsitePath('/politica-de-privacidade');
    this.firebaseService.log('POLITICA_PRIVACIDADE');
  }

  async openTermos() {
    this.mainService.openTrokaiWebsitePath('/termos-de-uso');
    this.firebaseService.log('TERMOS_DE_USO');
  }

  async goToLogin() {
    this.ionNav.push(LoginPage);
  }

  ngOnDestroy() {
    if (this.authSub) this.authSub.unsubscribe();
  }

  async googleLogin() {
    try {
      const googleUser = await SocialLogin.login({
        provider: 'google',
        options: { scopes: ['email', 'profile'], forceRefreshToken: true },
      });
      this.proceedToLogin(googleUser);
    } catch (ex) {
      console.log('ERRO GOOGLE');
      console.log(JSON.stringify(ex));
      this.toastService.makeToastErrorDefault();
      // this.alert.showAlert('ERRO GOOGLE', JSON.stringify(ex));
    }
  }

  async appleLogin() {
    console.log('--- TESTE APPLE ---');

    try {
      const options: SignInWithAppleOptions = {
        clientId: 'com.trokai.mobile',
        redirectURI: 'https://www.trokai.com.br',
        scopes: 'email name',
        state: '12345',
        nonce: 'nonce',
      };

      const res = await (await SignInWithApple.authorize(options)).response;

      console.log('--- RES APPLE ---');
      console.log(res);

      // https://developer.apple.com/documentation/signinwithapplerestapi/verifying_a_user
      // alert('Send token to apple for verification: ' + res.identityToken);

      if (res && res.identityToken) {
        const appleUser = {
          // always
          authorizationCode: res.authorizationCode,
          identityToken: res.identityToken,
          appleId: res.user,
          // first time
          email: res.email,
          givenName: res.givenName,
          familyName: res.familyName,
        };

        this.proceedToLoginApple(appleUser);
      } else {
        this.toastService.makeToastErrorDefault();
      }
    } catch (error) {
      this.toastService.makeToastErrorDefault();
      console.log(error);
    }
  }

  async proceedToLogin(gUser) {
    const loading = await this.loadingCtrl.create({
      keyboardClose: true,
      message: 'Autenticando...',
    });

    loading.present();

    try {
      const response = await this.authService.googleAuth(gUser.result.profile);

      if (response.isRegister) {
        this.router.navigateByUrl('/main/home', { replaceUrl: true });
        this.firebaseService.log('AUTH_GOOGLE_CADASTRO');
      } else {
        this.router.navigateByUrl('/main/home', { replaceUrl: true });
        this.firebaseService.log('AUTH_GOOGLE_LOGIN');
      }
    } catch {
      this.toastService.makeToast('Não foi possível logar');
    } finally {
      loading.dismiss();
    }
  }

  async proceedToLoginApple(appleUser) {
    const loading = await this.loadingCtrl.create({
      keyboardClose: true,
      message: 'Autenticando...',
    });

    loading.present();

    try {
      const response = await this.authService.appleAuth(appleUser);

      if (response.isRegister) {
        this.router.navigateByUrl('/main/home', { replaceUrl: true });
        this.firebaseService.log('AUTH_APPLE_CADASTRO');
      } else {
        this.router.navigateByUrl('/main/home', { replaceUrl: true });
        this.firebaseService.log('AUTH_APPLE_LOGIN');
      }
    } catch {
      this.toastService.makeToast('Não foi possível logar');
    } finally {
      loading.dismiss();
    }
  }
}

import { Component, OnDestroy, OnInit, inject } from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { OrderStatus, OrderStatusString } from '@trokai/shared-core';
import { BalanceModel, BankService } from '@trokai/shared-data-access';
import { UserService } from '@trokai/shared-data-access';
import {
  PagarMeKycDetailsStatus,
  PagarMeRecipientStatus,
  User,
} from '@trokai/shared-core';
import { BackButtonComponent } from '../shared/components/back-button/back-button.component';
import { CurrencyPipe, DatePipe } from '@angular/common';
import {
  IonButtons,
  IonContent,
  IonGrid,
  IonHeader,
  IonTitle,
  IonToolbar,
  IonLabel,
  IonRippleEffect, IonIcon, IonList, IonSpinner, IonButton } from '@ionic/angular/standalone';
import { addIcons } from 'ionicons';
import { informationCircleOutline, sadOutline } from 'ionicons/icons';
import { AlertService, CostPipe } from '@trokai/shared-ui';
import { TutorialService } from '../services/tutorial.service';
import { GlobalService } from '../services/global.service';
import { Subscription } from 'rxjs';

@Component({
  selector: 'app-bank',
  templateUrl: './bank.page.html',
  styleUrls: ['./bank.page.scss'],
  standalone: true,
  imports: [IonButton, IonSpinner, IonList, IonIcon, 
    IonLabel,
    IonHeader,
    IonToolbar,
    IonButtons,
    IonTitle,
    IonContent,
    IonGrid,
    BackButtonComponent,
    CurrencyPipe,
    DatePipe,
    CostPipe,
  ],
})
export class BankPage implements OnInit, OnDestroy {
  isLoading = true;
  balance: BalanceModel;

  ordersAndTransfers = [];

  user: User;

  docsPending = false;
  docsRefused = false;
  shouldVerify = false;
  allGood = false;
  docsUrl = null;

  stateSubs: Subscription;

  private tutorialService = inject(TutorialService);
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private bankService = inject(BankService);
  private alert = inject(AlertService);
  private userService = inject(UserService);
  private globalService = inject(GlobalService);

  constructor() {
    addIcons({ informationCircleOutline, sadOutline });
  }

  async ngOnInit() {
    this.tutorialService.bankPresentation();
    this.bankService.balance.subscribe((balance) => {
      if (!balance) return;
      this.balance = balance;
      this.mountList();
    });

    this.stateSubs = this.globalService.onAppStateChange.subscribe((state) => {
      // when user comes back to the app after verifying documents
      if (state.isActive) this.load();
    });
  }

  async mountList() {
    const orders = [];
    const transfers = [];

    for (const t of this.balance.transfers) {
      const obj = {
        title: 'Saque',
        date: t.createdAt,
        text: this.bankService.getGatewayStatusString(t.status),
        amount: t.amount,
        items: t.ordersIds.map((id) => {
          const order = this.balance.orders?.find((o) => o._id === id);
          return order?.items.map((item) => (item.description + (item.refund ? ' (Estornado)' : '')));
        }),
      };

      transfers.push(obj);
    }

    for (const t of this.balance.orders) {
      const obj = {
        title: 'Venda',
        text: OrderStatusString[t.status],
        date: t.createdAt,
        items: t.items.map((item) => (item.description + (item.refund ? ' (Estornado)' : ''))),
        amount: t.sellerProfit,
        transferAt: this.checkOrderTransferAt(t),
      };

      orders.push(obj);
    }

    const auxList = [].concat(orders, transfers);
    // sort created at more recent
    auxList.sort((a, b) => (a.date < b.date ? 1 : -1));

    this.ordersAndTransfers = auxList;
  }

  checkOrderTransferAt(order) {
    const notTransfered =
      this.balance.transfers.filter((t) => t.ordersIds.includes(order._id))
        .length === 0;

    const statusMatch = [
      OrderStatus.PAYMENT_APPROVED,
      OrderStatus.WAITING_SHIPMENT,
      OrderStatus.WAITING_WITHDRAWAL,
      OrderStatus.ORDER_SENT,
      OrderStatus.ORDER_DELIVERED,
      OrderStatus.WAITING_REVIEW,
      OrderStatus.CONCLUDED,
    ].includes(order.status);

    if (statusMatch && notTransfered) return order.transferAt;
    return null;
  }

  alertSaqueIndisponivel() {
    this.alert.showAlert(
      'Saldo insuficiente',
      'Não há saldo disponível para saque.',
    );
  }

  alertSaquePrevisao() {
    this.alert.showAlert(
      'Previsão de saque',
      'O valor de uma venda é liberado 10 dias úteis após o recebimento do produto pelo comprador.',
    );
  }

  ionViewDidEnter() {
    this.load();
  }

  async load() {
    this.bankService.fetchBalance().subscribe();

    try {
      this.isLoading = true;

      const user = await this.userService.getUserInfo();
      const { pagarMeRecipientStatus, pagarMeKycDetailsStatus } = user;

      const _recipient = PagarMeRecipientStatus;
      const _kyc = PagarMeKycDetailsStatus;

      this.allGood = pagarMeRecipientStatus === _recipient.ACTIVE;
      this.docsRefused = pagarMeRecipientStatus === _recipient.REFUSED;

      this.docsPending =
        pagarMeRecipientStatus === _recipient.AFFILIATION &&
        pagarMeKycDetailsStatus === _kyc.PENDING;

      this.shouldVerify =
        pagarMeRecipientStatus === _recipient.AFFILIATION &&
        pagarMeKycDetailsStatus === _kyc.PARTIALLY_DENIED;

      if (this.shouldVerify)
        this.docsUrl = (await this.bankService.fetchPagarmeDocumentsURL()).url;
    } finally {
      this.isLoading = false;
    }
  }

  async withdraw() {
    if (this.allGood && this.balance.saldoDisponivel > 0) {
      this.router.navigate(['bank-account'], { relativeTo: this.route });
    }
  }

  ngOnDestroy(): void {
    this.stateSubs?.unsubscribe();
  }
}

