export class CartsPage implements OnDestroy, OnInit {
  private buyingService = inject(BuyingService);
  private router = inject(Router);
  private searchService = inject(SearchService);
  private route = inject(ActivatedRoute);
  private authService = inject(AuthService);
  private completingInformation = inject(CompletingInformationService);
  private mainService = inject(MainService);
  private modalCtrl = inject(ModalController);
  private loading = inject(LoadingService);

  baskets: Basket[];

  // suggestions
  suggestionHeader;
  suggestionLink;
  suggestions = [];

  subs: Subscription;

  ngOnInit() {
    addIcons({ sadOutline, closeOutline });
    this.subs = this.buyingService.baskets$.subscribe((baskets) =>
      this.mount(baskets),
    );

    if (this.authService.getUserValue())
      this.buyingService.getMyReserves(); // to update previous reserves
  }

  goToWardrobe(userId) {
    this.mainService.navigateToWardrobe(userId);
  }

  async mount(baskets: Basket[]) {
    const params = this.route.snapshot.queryParams;

    // if came from other paths
    if (!params || !params['from']) {
      this.baskets = baskets;
      return;
    }

    // if came from product or wardrobe
    const suggOwner = params['from'];
    const suggBasket = baskets.find((b) => b.owner._id === suggOwner);

    if (!suggBasket) {
      this.baskets = baskets;
      this.suggestions = [];
      this.suggestionHeader = null;
      this.suggestionLink = null;
      return;
    }

    try {
      const exclude = suggBasket.products.map((p) => p._id);
      const filter = new Filters({
        status: ClothesStatus.PUBLISHED,
        sell: true,
      });

      this.suggestions = (
        await this.searchService.getClothesOfUser(
          suggOwner,
          0,
          12,
          filter,
          exclude,
        )
      ).clothes;

      // shows suggestions instead of other baskets
      if (this.suggestions.length > 0) {
        this.suggestionHeader = `Mais de ${suggBasket?.owner?.storeName}`;
        this.suggestionLink = `/users/${suggBasket?.owner?.nickname}`;
      } else {
        this.suggestionHeader = null;
        this.suggestionLink = null;
      }

      this.baskets = [suggBasket];
    } catch { /* intentional */ }
  }

  async checkout(ownerId: string) {
    await this.completingInformation.tryStartPurchase(ownerId);
  }

  async openWardrobe(owner: User) {
    this.mainService.navigateToWardrobe(owner._id);
  }

  async open(product) {
    const modal = await this.modalCtrl.create({
      component: ItemViewerComponent,
      cssClass: 'modal-85',
      componentProps: {
        product: product,
        canFavorite: true,
        canEdit: false,
        canShare: false,
      },
    });

    modal.present();
  }

  removeProduct(product: Clothes) {
    this.buyingService.removeProduct(product);
  }

  ngOnDestroy(): void {
    if (this.subs) this.subs.unsubscribe();
  }

}

import { inject, Injectable } from '@angular/core';
import { NavController } from '@ionic/angular/standalone';
import { App } from '@capacitor/app';
import { NavigationManager, NavOptions, User } from '@trokai/shared-core';
import { AuthService } from '../services/auth.service';

/** Mobile implementation of NavigationManager — Ionic NavController stacks + Capacitor hardware back. */
@Injectable()
export class MobileNavigationManager extends NavigationManager {
  private nav = inject(NavController);
  private auth = inject(AuthService);

  // app checkLogged() already prompts (askToLogin) when not logged
  ensureAuthenticated(): boolean {
    return this.auth.checkLogged();
  }

  isAuthenticated(): boolean {
    return this.auth.isLogged();
  }

  currentUserId(): string | undefined {
    return this.auth.getUserValue()?._id;
  }

  currentUser(): User | undefined | null {
    return this.auth.getUserValue();
  }

  async syncUserData(): Promise<void> {
    await this.auth.syncUserData();
  }

  async forward(commands: unknown[], opts?: NavOptions): Promise<boolean> {
    await this.nav.navigateForward(commands as any[], {
      queryParams: opts?.queryParams,
      replaceUrl: opts?.replaceUrl,
    });
    return true;
  }

  async back(): Promise<void> {
    // Prefer popping the Ionic stack; fall back to platform back.
    await Promise.resolve(this.nav.pop()).catch(() => this.nav.back());
  }

  async root(commands: unknown[], opts?: NavOptions): Promise<boolean> {
    await this.nav.navigateRoot(commands as any[], {
      queryParams: opts?.queryParams,
    });
    return true;
  }

  registerHardwareBack(handler: () => boolean): void {
    // handler() returns true if it consumed the event; otherwise default back.
    App.addListener('backButton', () => {
      if (!handler()) {
        this.nav.back();
      }
    });
  }
}

