  IonSpinner,
  IonTitle,
  IonToolbar,
  LoadingController,
  ModalController,
  NavController,
  IonButton,
  IonIcon,
  IonButtons,
  ActionSheetController,
  IonList,
  IonRippleEffect,
  IonLabel,
  IonBadge,
  IonText,
} from '@ionic/angular/standalone';
import { addIcons } from 'ionicons';
import {
  alertCircle,
  alertCircleOutline,
  arrowUndo,
  cartOutline,
  cashOutline,
  chevronForward,
  close,
  closeCircle,
  copyOutline,
  createOutline,
  ellipsisHorizontal,
  pauseOutline,
  playOutline,
  refreshOutline,
  resize,
  shareSocial,
  shieldCheckmark,
  timeOutline,
  trashOutline,
} from 'ionicons/icons';
