    this.firebaseService.log('SHARE_TROKAI');
  }

  async logout() {
    const answer = await this.alertService.askQuestion(
      'Logout',
      'Deseja mesmo sair dessa conta?',
    );
    if (answer) this.authService.logout();
  }
}

