@Component({
  selector: 'app-filter',
  templateUrl: './filter.component.html',
  styleUrls: ['./filter.component.scss'],
  standalone: true,
  imports: [
    IonHeader,
    IonToolbar,
    IonButtons,
    IonButton,
    IonIcon,
    IonTitle,
    IonToggle,
    IonBadge,
    IonRadioGroup,
    IonItem,
    IonRadio,
    IonRippleEffect,
    IonRange,
    IonContent,
    IonFooter,
    IonItem,
    IonLabel,
    FormsModule,
    NgClass,
    IonRow,
    CostPipe,
    CurrencyPipe,
  ],
})
export class FilterComponent implements OnInit, OnDestroy, AfterViewInit {
  private modalCtrl = inject(ModalController);
  private toastService = inject(ToastService);
  private globalService = inject(GlobalService);

  itemsMap = null;
  sizes = [];
  pieces = [];

  @Input() filter = new Filters();

  sections = {
    condition: false,
    gender: false,
    category: false,
    size: false,
    cost: false,
    location: false,
  };

  category: any = {};

  itemsMapSub: Subscription;

  costRange = { lower: null, upper: null };
  maxCost = 21000;

  ngOnInit() {
    addIcons({ close, helpCircleOutline, chevronUp, chevronDown });
    this.itemsMapSub = this.globalService
      .itemsMap()
      .subscribe((items) => (this.itemsMap = items));
    this.resetLocalFilter();
  }

  ngAfterViewInit(): void {
    this.costRange.lower = this.filter.costLower ?? 0;
    this.costRange.upper = this.filter.costUpper ?? this.maxCost;
  }

  resetLocalFilter() {
    if (!this.filter.size) this.filter.size = [];
    if (!this.filter.piece) this.filter.piece = [];
    if (!this.filter.gender) this.filter.gender = [];
    if (!this.filter.condition) this.filter.condition = [];

    if (this.filter.category != null) {
      this.category = {
        ...this.itemsMap.category.find(
          (cat) => cat._id === this.filter.category,
        ),
      };
      if (this.category != null) this.mountPieces();

      if (this.filter.age != null) this.mountSizes(this.filter.age);
    }
  }

  mountSizes(ageSelected) {
    if (ageSelected !== this.filter.age) {
      this.filter.size = [];
      this.filter.age = ageSelected;
    }

    this.sizes = [];

    if (!this.category['sizes'] || this.category['sizes'].length === 0) return;

    const ageSizes = this.category['sizes'][ageSelected];
    ageSizes.forEach((size) =>
      this.sizes.push({ sizeId: size._id, sizeValue: size.value }),
    );

    this.sizes = [...this.category['sizes'][ageSelected]];
  }

  mountPieces() {
    if (this.category)
      this.pieces = [...this.category['pieces']].sort((a, b) =>
        a.value > b.value ? 1 : -1,
      );
    else this.pieces = [];
  }

  filtersOn() {
    return this.filter.enabled();
  }

  clear() {
    this.filter = new Filters({ status: this.filter.status });
    this.toastService.makeToast('Filtros removidos');
    this.close(true);
  }

  close(filtersChanged = false) {
    this.modalCtrl.dismiss({
      filters: this.filter,
      filtersChanged: filtersChanged,
    });
  }

  openSection(section) {
    this.sections[section] = !this.sections[section];
  }

  changeCategory(catId) {
    if (catId == null) return;
    const cat = this.itemsMap.category.find((item) => item._id === catId);
    this.selectCategory(cat);
  }

  selectCategory(cat) {
    if (this.category && this.category['_id'] == cat._id) {
      this.category = null;
      this.filter.category = null;
      this.filter.age = null;
    } else {
      this.category = { ...cat };
      this.filter.category = cat._id;
    }

    this.sizes = [];
    this.filter.size = [];
    this.filter.piece = [];
    this.filter.gender = [];
    this.filter.condition = [];

    if (this.filter.age != null) this.mountSizes(this.filter.age);

    this.mountPieces();
  }

  helpSize(event) {
    event.stopPropagation();

    if (this.filter.category == null) {
      this.toastService.makeToast(
        'Selecione uma categoria para ver os tamanhos.',
      );
    } else if (
      this.filter.category !== null &&
      (!this.category['sizes'] || this.category['sizes'].length === 0)
    ) {
      this.toastService.makeToast(
        'Categoria ' + this.category['value'] + ' não possui tamanhos',
      );
    } else {
      this.toastService.makeToast(
        'Selecione a faixa etária para ver os tamanhos',
      );
    }
  }

  changeCost(ev) {
    this.filter.costLower =
      ev.target.value.lower > 0 ? ev.target.value.lower : null;
    this.filter.costUpper =
      ev.target.value.upper < this.maxCost ? ev.target.value.upper : null;
  }

  applyFilters() {
    this.close(true);
    this.toastService.makeToast('Filtros aplicados');
  }

  select(property: string, item?: BasicModel) {
    if (Filters.booleanFilters.includes(property)) {
      if (!this.filter[property]) this.filter[property] = true;
      else delete this.filter[property];
      return;
    }

    if (Filters.singleChoiceFilters.includes(property))
      this.selectSingle(property, item);
    else this.selectMultiple(property, item);
  }

  selectMultiple(property: string, item: BasicModel) {
    const index = this.filter[property].findIndex(
      (el) => el.toString() === item._id.toString(),
    );

    if (index >= 0) {
      this.filter[property].splice(index, 1);
    } else {
      const els = [...this.filter[property]];
      els.push(item._id);
      this.filter[property] = els;
    }
  }

  // special, gender, condition
  selectSingle(property: string, item: BasicModel) {
    if (this.filter[property] == null) this.filter[property] = item._id;
    else if (this.filter[property] === item._id) this.filter[property] = null;
    else this.filter[property] = item._id;
  }

  private multipleSelected(property: string, item: BasicModel) {
    if (!notNullOrEmpty(this.filter[property])) return false;

    if (Array.isArray(this.filter[property])) {
      return this.filter[property].find((el) => el === item._id) != null;
    } else {
      return this.filter[property] === item._id;
    }
  }
  selected(property: string, item: BasicModel) {
    if (Filters.singleChoiceFilters.includes(property))
      return this.filter[property] === item._id;
    else return this.multipleSelected(property, item);
  }

  ngOnDestroy(): void {
    if (this.itemsMapSub) this.itemsMapSub.unsubscribe();
  }
}

import { AuthResponseData, StorageService, User } from '@trokai/shared-core';
import { UserService } from '@trokai/shared-data-access';
import { inject, Injectable } from '@angular/core';
import { BehaviorSubject, from, lastValueFrom, of } from 'rxjs';
import { map, tap, take } from 'rxjs/operators';
import { HttpClient } from '@angular/common/http';
import { environment } from 'src/environments/environment';
import { NavController, Platform } from '@ionic/angular/standalone';
import { AlertService } from '@trokai/shared-ui';
import { PushNotificationsService } from './push-notifications.service';
import { SocialLogin } from '@capgo/capacitor-social-login';

@Injectable({ providedIn: 'root' })
export class AuthService {
  private http = inject(HttpClient);
  private userService = inject(UserService);
  private platform = inject(Platform);
  private alertService = inject(AlertService);
  private pushService = inject(PushNotificationsService);
  private navCtrl = inject(NavController);
  private storage = inject(StorageService);

  validatingPhone = '';
  validatingUser = {};

  redirectUrlPicture = null;
  hasPassword = null;

  private _user = new BehaviorSubject<User>(null); // atualiza os objetos de usuario
  private _logged = new BehaviorSubject<boolean>(null); // atualiza o usuario apenas login/logout

  get logged() {
    return this._logged.asObservable();
  }

  get user() {
    return this._user.asObservable();
  }

  // used to verify apple token
  async checkUserTokens() {
    this.http.get(environment.urlApi + '/users/sync').subscribe();
  }

  // used to fech updated data
  async syncUserData() {
    const updatedUser = await this.userService.getUserInfo();
    updatedUser.token = this._user.getValue().token;

    this._user.next(updatedUser);
  }

  syncAvatar(avatar) {
    this.user.pipe(take(1)).subscribe((u) => {
      u.avatar = avatar;
      this._user.next(u);
    });
  }

  login(email: string, password: string) {
    return this.http
      .post<AuthResponseData>(environment.urlApi + '/users/login', {
        email: email,
        password: password,
      })
      .pipe(tap(this.setUserData.bind(this)));
  }

  googleAuth(gUser) {
    return lastValueFrom(
      this.http
        .post<AuthResponseData>(environment.urlApi + '/users/google', { gUser })
        .pipe(tap(this.setUserData.bind(this))),
    );
  }

  appleAuth(appleUser) {
    return lastValueFrom(
      this.http
        .post<AuthResponseData>(environment.urlApi + '/users/apple', {
          appleUser,
        })
        .pipe(tap(this.setUserData.bind(this))),
    );
  }

  async userHasPassword() {
    this.hasPassword = await this.userService.userHasPassword();
    return this.hasPassword;
  }

  async register(name: string, email: string, password: string) {
    const res = await this.userService.register(name, email, password);
    await this.setUserData(res);
    return res;
  }

  async updateUser(user) {
    const res = await this.userService.updateUser(user);
    await this.syncUserData();
    return res;
  }

  private async setUserData(userData: AuthResponseData) {
    const user = userData.user;
    user.token = userData.token;

    this._user.next(user);
    this._logged.next(true);

    await this.storeAuthData(user._id, user.name, user.email, user.token);
  }

  async storeAuthData(
    userId: string,
    name: string,
    email: string,
    token: string,
  ) {
    const storedJ = await this.storage.getObject<{ userId: string }>('authData');

    if (storedJ) {
      if (storedJ['userId'].toString().trim() !== userId.toString().trim()) {
        await this.storage.clear();
      }
    }

    await this.storage.setObject('authData', {
      userId: userId,
      name: name,
      email: email,
      token: token,
    });
  }

  async logout(deletedAccount = false) {
    try {
      try {
        // if deleted account, has already been dissociated
        if (!deletedAccount) await this.pushService.userDissociate();
        await SocialLogin.logout({ provider: 'google' });
      } catch (err) {
        console.log('Erro sign out - ', err);
      }

      this.hasPassword = null;
      this._logged.next(null);
      this._user.next(null);
      await this.storage.clear();
    } catch { /* intentional */ }
  }

  autoLogin() {
    // from resolve uma promise e retorna uma observable
    return from(
      this.storage.getObject<{
        userId: string;
        name: string;
        email: string;
        token: string;
      }>('authData'),
    ).pipe(
      tap((user) => {
        if (user) {
          const aux = new User();
          aux.token = user.token;

          this._user.next(aux);

          this.userService.getUserInfo().then(async (u) => {
            // verifica se as informacoes do storage estao corretas
            // se o chat esta atualizado ou se o login e o mesmo do storage
            await this.storeAuthData(u._id, u.name, u.email, user.token);

            u.token = user.token;

            this._user.next(u);
            this._logged.next(true);
          });
        }
      }),
      map((user) => {
        return !!user;
      }),
    );
  }

  // Retorna o valor atual do user
  getUserValue(): User {
    return this._user.getValue();
  }

  isLogged() {
    return this._logged.getValue();
  }

  async uploadAvatar(image) {
    const res = await this.userService.uploadAvatar(image);
    this.syncAvatar(res.imageName);
    return res;
  }

  async deleteAccount() {
    await this.userService.deleteAccount(this.getUserValue()._id);
    this.logout(true);
  }

  checkLogged() {
    const logged = !!this.getUserValue();

    if (!logged) this.askToLogin();

    return logged;
  }

  async askToLogin() {
    const login = await this.alertService.askQuestion(
      'Entre no Trokaí',
      'Faça login ou crie uma conta para aproveitar todos os recursos do Trokaí',
      'Entrar agora',
      'Agora não',
    );

    if (login) this.navCtrl.navigateRoot('/main/auth');
  }
}

