import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { Geolocation } from '@capacitor/geolocation';
import { LoadingController, Platform } from '@ionic/angular/standalone';
import { BehaviorSubject, lastValueFrom, map } from 'rxjs';
import { AuthService } from 'src/app/services/auth.service';
import { environment } from 'src/environments/environment';
import { ToastService } from './toast-service';

import {
  RespostaCep,
  SearchLocation,
  StorageService,
} from '@trokai/shared-core';

@Injectable({
  providedIn: 'root',
})
export class GeolocationService {
  private http = inject(HttpClient);
  private platform = inject(Platform);
  private toastService = inject(ToastService);
  private authService = inject(AuthService);
  private storage = inject(StorageService);

  private _searchLocation = new BehaviorSubject<SearchLocation | null>(null);
  private _user;

  get searchLocation() {
    return this._searchLocation.asObservable();
  }

  constructor() {
    this.authService.user.subscribe((u) => {
      if (!u) return;

      if (
        u &&
        u.address &&
        this._user &&
        (!this._user ||
          !this._user.address ||
          (this._user.address &&
            this._user.address.zipCode !== u.address.zipCode))
      )
        // se o usuario tiver um endereco e for diferente do endereco atual, atualiza a localizacao de busca
        this.setSearchLocation(
          u.address.location.coordinates[1],
          u.address.location.coordinates[0],
          u.address.zipCode,
        );

      this._user = u;
    });
  }

  // private methods

  private async getAddressFromLatLng(lat, lng) {
    return lastValueFrom(
      this.http
        .get(`https://maps.googleapis.com/maps/api/geocode/json?latlng=${lat},${lng}
    &key=${environment.mapsGeocodingKey}&result_type=street_address`),
    );
  }

  private async getLatLngFromCep(cep: number) {
    return lastValueFrom(
      this.http.get(
        `https://maps.googleapis.com/maps/api/geocode/json?address=${cep}
      &components=country:BR&key=${environment.mapsGeocodingKey}`,
      ),
    );
  }

  private async checkGpsPermission(): Promise<boolean> {
    if (!(this.platform.is('mobile') && this.platform.is('hybrid'))) {
      this.toastService.makeToast('Sem permissão para localização');
      return false;
    }

    // verifica permissao de gps
    let permissions = await Geolocation.checkPermissions();

    // se nao tiver permissao, solicita permissao
    if (permissions.location !== 'granted')
      permissions = await Geolocation.requestPermissions();

    // se permissao aceita
    if (permissions.location === 'granted') return true;

    this.toastService.makeToast('Sem permissão para localização');
    return false;
  }

  private async getGpsCoordinates(): Promise<SearchLocation> {
    try {
      const coordinates = await Geolocation.getCurrentPosition();

      return new SearchLocation(
        coordinates.coords.latitude,
        coordinates.coords.longitude,
      );
    } catch {
      return null;
    }
  }

  private async setSearchLocation(lat: number, lng: number, zip: number) {
    const newLocation = new SearchLocation(lat, lng, zip);
    this._searchLocation.next(newLocation);

    await this.storage.setObject('searchLocation', newLocation);
  }

  private async getStoredSearchLocation(): Promise<SearchLocation> {
    return this.storage.getObject<SearchLocation>('searchLocation');
  }

  // public methods

  public async init() {
    try {
      const user = this.authService.getUserValue();

      // home address
      if (user && user.address) {
        const lat = user.address.location.coordinates[1];
        const lng = user.address.location.coordinates[0];
        const zip = user.address.zipCode;
        await this.setSearchLocation(lat, lng, zip);
        return;
      }

      // check storage for last search location
      const storedLocation = await this.getStoredSearchLocation();

      // if there is a stored location, use it
      if (storedLocation) {
        await this.setSearchLocation(
          storedLocation.lat,
          storedLocation.lng,
          storedLocation.zip,
        );
        return;
      }

      // GPS
      if (await this.checkGpsPermission()) {
        const gpsLocation = await this.getGpsCoordinates();

        if (gpsLocation) {
          const res: any = await this.getAddressFromLatLng(
            gpsLocation.lat,
            gpsLocation.lng,
          );

          const zip =
            +res.results[0].address_components[6].short_name.replace('-');

          await this.setSearchLocation(gpsLocation.lat, gpsLocation.lng, zip);
          return;
        }
      }
    } catch (error) {
      console.log(error);
    }
  }

  public async getAddressFromZip(zipCode): Promise<RespostaCep> {
    return lastValueFrom(
      this.http.get<RespostaCep>(`https://viacep.com.br/ws/${zipCode}/json/`),
    );
  }

  public async changeSearchZip(zipCode: number) {
    try {
      const res: any = await this.getLatLngFromCep(zipCode);

      if (res.results.length === 0) {
        this.toastService.makeToast('CEP não encontrado');
        return;
      }

      const lat = res.results[0].geometry.location.lat;
      const lng = res.results[0].geometry.location.lng;

      await this.setSearchLocation(lat, lng, zipCode);
    } catch (error) {
      console.log(error);
      this.toastService.makeToast('Erro ao buscar CEP');
    }
  }

  public getSearchLocationValue(): SearchLocation | null {
    return this._searchLocation.getValue();
  }

  public reset() {
    this._searchLocation.next(null);
    this.init();
  }
}

import {
  HomePayloadRow,
  HomePayloadRowItem,
} from '@trokai/shared-core';
import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { lastValueFrom } from 'rxjs';
import { environment } from 'src/environments/environment';
import { Router } from '@angular/router';
import { SearchService } from './search.service';
import { Browser } from '@capacitor/browser';
import { SearchPageService } from './search-page.service';
import { MainService } from './main.service';
import { GeolocationService } from './geolocation.service';

export { HomePayloadRow, HomePayloadRowItem };

@Injectable({
  providedIn: 'root',
})
export class HomeService {
  private http = inject(HttpClient);
  private mainService = inject(MainService);
  private geolocationService = inject(GeolocationService);

  fetchHome() {
    const searchLocation = this.geolocationService.getSearchLocationValue();

    let params = {};

    if (searchLocation) {
      params = {
        placeLat: searchLocation.lat,
        placeLng: searchLocation.lng,
      };
    }

    return lastValueFrom(
      this.http.get<{ home: HomePayloadRow[]; alert: string; updatedAt: Date }>(
        `${environment.urlApi}/home`,
        { params },
      ),
    );
  }

  async navigate(item: HomePayloadRow | HomePayloadRowItem) {
    if (!item.actionUrl) return;

    const urlObj = new URL(item.actionUrl);

    if (urlObj.hostname.includes('trokai.com')) {
      this.mainService.processLink(urlObj, item.actionUrl);
    } else {
      Browser.open({ url: item.actionUrl });
    }
  }
}

import { Clothes } from '@trokai/shared-core';
import { SellerFees } from '@trokai/shared-core';
import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject, Subject, lastValueFrom, map } from 'rxjs';
import { environment } from 'src/environments/environment';
import { Filters, SearchResponse, UploadPictureItem } from '@trokai/shared-core';
import { AlertService } from '@trokai/shared-ui';
import { GlobalService } from './global.service';
import { CatalogService } from '@trokai/shared-data-access';


/**
 * A picture slot as perceived by the upload pipeline.
 *
 * - `blob !== null`  → new or re-cropped image; always sent as a file upload.
 * - `blob === null`  → unmodified server image; identified by `serverId`.
 *                      On PATCH the backend keeps it in place via its _id.
 *                      `serverUrl` (.lg) lets us re-fetch the blob for duplication/cropping.
 */
export { ClothesStatus } from '@trokai/shared-core';

export { ClothesPayment } from '@trokai/shared-data-access';

@Injectable({
  providedIn: 'root',
})
export class InventoryService {
  private http = inject(HttpClient);
  private globalService = inject(GlobalService);
  private alertService = inject(AlertService);
  private catalog = inject(CatalogService);

  public _recentProducts = new BehaviorSubject<
    Map<string, Clothes | undefined>
  >(new Map());

  item: Clothes = new Clothes();
  /** Upload pipeline buffer. Holds UploadPictureItem[] while editing/creating an item. */
  pendingPictures: UploadPictureItem[] = [];

  // delegate to CatalogService (single source); '' preserves old contract
  getGenderName(gender: number) {
    return this.catalog.getGenderName(gender) ?? '';
  }

  getConditionName(condition: number) {
    return this.catalog.getConditionName(condition) ?? '';
  }

  getAgeName(age: number) {
    return this.catalog.getAgeName(age) ?? '';
  }

  getCategoryName(category: number) {
    return this.catalog.getCategoryName(category) ?? '';
  }

  getPieceName(piece: number, category: number) {
    return this.catalog.getPieceName(piece, category) ?? '';
  }

  getSizeName(size: number, category: number, age: number) {
    return this.catalog.getSizeName(size, category, age) ?? '';
  }

  updateClothe(id, formData) {
    return this.http.patch<Clothes>(
      environment.urlApi + '/products/' + id,
      formData,
    );
  }

  addClothe(formData) {
    return this.http.post<Clothes>(environment.urlApi + '/products', formData);
  }

  resetItem() {
    this.item = new Clothes();
    this.pendingPictures = [];
  }

  checkInventoryLimit() {
    return this.http
      .get(environment.urlApi + '/users/me/verify-clothes-limit')
      .pipe(
        map((res) => {
          if (!res['allowed'])
            this.alertService.showAlert('Armário cheio', res['message']);

          return res['allowed'];
        }),
      );
  }

  async deleteItem(item) {
    try {
      await lastValueFrom(
        this.http.delete(`${environment.urlApi}/clothes/${item._id}`),
      );

      this._recentProducts.next(
        new Map(this._recentProducts.value).set(item._id, undefined),
      );
    } catch { /* intentional */ }
  }

  async duplicate() {
    // All blobs must have been pre-fetched by startDuplicate before navigating to the form.
    // If any slot is still missing a blob, the pre-fetch failed — abort rather than silently
    // sending a broken or incomplete item.
    const missing = this.pendingPictures.some((s) => !s.blob);
    if (missing)
      throw new Error(
        'Não foi possível carregar todas as imagens para duplicar o anúncio',
      );

    delete this.item._id;
    await this.upload();
  }

  async upload(): Promise<Clothes> {
    const formData = new FormData();
    const pictures = this.pendingPictures;
    const isEdit = !!this.item._id;

    if (isEdit) {
      // ── PATCH ──────────────────────────────────────────────────────────────
      // Tell the backend exactly what to do with each slot:
      //   { op: 'keep', filename }  → reuse the existing server file as-is
      //   { op: 'new',  blobIndex } → replace/insert with the blob at that index
      // Only new blobs are transmitted; kept images are referenced by filename.
      let blobIndex = 0;
      const picturesMap = pictures.map((slot) => {
        if (slot.blob) {
          formData.append('images', slot.blob);
          return { op: 'new', blobIndex: blobIndex++ };
        }
        return { op: 'keep', id: slot.serverId };
      });
      formData.append('pictures_map', JSON.stringify(picturesMap));
    } else {
      // ── POST ───────────────────────────────────────────────────────────────
      // New item: every slot must have a blob — append them in order.
      for (const slot of pictures) {
        if (slot.blob) formData.append('images', slot.blob);
      }
    }

    const newItem = { ...this.item };
    delete newItem.images;

    const itemId = newItem._id;
    if (itemId) delete newItem._id;

    formData.append('body', JSON.stringify(newItem));

    try {
      let response;

      if (this.item._id) {
        this.resetItem();
        response = await lastValueFrom(this.updateClothe(itemId, formData));
      } else {
        response = await lastValueFrom(this.addClothe(formData));
      }

      if (response?._id) {
        this._recentProducts.next(
          new Map(this._recentProducts.value).set(response._id, response),
        );
      }

      return response;
    } catch {
      throw new Error('Erro ao publicar anúncio');
    }
  }

  async startDuplicate(selectedItem: Clothes) {
    this.item.copyOf = selectedItem._id;
    this.startEditing(selectedItem);

    // Pre-fetch all server images as blobs before navigating to the form so the
    // image picker treats each picture as a brand-new local image (serverId = null).
    // This prevents any reference to the original item's server files.
    const pictures = this.pendingPictures.slice();
    for (let i = 0; i < pictures.length; i++) {
      const slot = pictures[i];
      if (!slot.blob && slot.serverUrl) {
        try {
          const res = await fetch(`${slot.serverUrl}?${Date.now()}`);
          const raw = await res.blob();
          const blob = new Blob([raw], {
            type: raw.type.startsWith('image/') ? raw.type : 'image/jpeg',
          });
          pictures[i] = {
            blob,
            serverId: null,
            serverUrl: slot.serverUrl,
            smUrl: slot.smUrl,
          };
        } catch {
          /* keep original slot — duplicate() will retry on submit */
        }
      }
    }
    this.pendingPictures = pictures;
  }

  // Prepara o objeto para ser editado
  startEditing(selectedItem) {
    this.item.age = selectedItem.age;
    this.item.category = selectedItem.category;
    this.item.condition = selectedItem.condition;
    this.item.cost = selectedItem.cost;
    this.item.description = selectedItem.description;
    this.item.gender = selectedItem.gender;
    this.item.piece = selectedItem.piece;
    this.item.sell = selectedItem.sell;
    this.item.size = selectedItem.size;
    this.item.title = selectedItem.title;
    this.item.weight = selectedItem.weight;
    this.item.declaredValue = selectedItem.declaredValue;
    this.item.firstCost = selectedItem.firstCost;
    this.item._id = selectedItem._id;
    this.item.brand = selectedItem.brand;

    this.pendingPictures = (selectedItem.images ?? [])
      .filter((img) => img?.sm || img?.lg)
      .map(
        (img): UploadPictureItem => ({
          blob: null,
          serverId: img._id ?? null,
          serverUrl: img.lg ?? null,
          smUrl: img.sm ?? null,
        }),
      );
  }

  getSellerFees(cost) {
    return lastValueFrom(
      this.http.get<SellerFees>(
        `${environment.urlApi}/payments/seller-fees?value=${cost}`,
      ),
    );
  }

  // Transforma a url web da imagem em Base 64
  getBase64FromURL(imgUrl) {
    const img = new Image();

    return new Promise((resolve, reject) => {
      img.addEventListener(
        'load',
        function () {
          const canvas = document.createElement('canvas');
          canvas.width = img.width;
          canvas.height = img.height;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, 0, 0);
          const dataURL = canvas.toDataURL('image/jpeg');

          resolve(dataURL);
        },
        false,
      );

      // set attributes and src
      img.setAttribute('crossOrigin', 'Anonymous');

      img.src = imgUrl + '?' + new Date().getTime().toString();
    });
  }

  renewProduct(productId) {
    return lastValueFrom(
      this.http.patch(
        environment.urlApi + '/clothes/' + productId + '/renew',
        {},
      ),
    );
  }

  deactivateProduct(productId) {
    return lastValueFrom(
      this.http.patch(
        environment.urlApi + '/clothes/' + productId + '/deactivate',
        {},
      ),
    );
  }

  activateProduct(productId) {
    return lastValueFrom(
      this.http.patch(
        environment.urlApi + '/clothes/' + productId + '/activate',
        {},
      ),
    );
  }

  renewAll(userId) {
    return lastValueFrom(
      this.http.patch(`${environment.urlApi}/clothes/renew/user/${userId}`, {}),
    );
  }

  async getMyClothes(
    skip = 0,
    limit = 30,
    filter?: Filters,
    exclude = [],
  ): Promise<SearchResponse> {
    const response = await lastValueFrom(
      this.http.get<SearchResponse>(`${environment.urlApi}/products/me`, {
        params: {
          skip,
          limit,
          ...filter,
          exclude,
        },
      }),
    );

    const recentProducts = this._recentProducts.value;

    if (recentProducts.size > 0) {
      const existingIds = new Set(response.clothes.map((c) => c._id));

      const toInject: Clothes[] = [];

      for (const [id, product] of recentProducts) {
        if (existingIds.has(id)) {
          if (product === undefined) {
            response.clothes = response.clothes.filter((c) => c._id !== id);
            response.count--;
          }
        } else if (product) {
          toInject.push(product);
        }
      }

      if (toInject.length > 0) {
        response.clothes = [...toInject, ...response.clothes];
        response.count += toInject.length;
      }
    }

    return response;
  }

  reset() {
    this._recentProducts.next(new Map());
  }
}

import { inject, Injectable } from '@angular/core';
import { Router } from '@angular/router';
import { LoadingController, NavController } from '@ionic/angular/standalone';
import { Subject } from 'rxjs';
import { FirebaseService } from './firebase.service';
import { SearchPageService } from './search-page.service';
import { SearchService } from './search.service';
import { Browser } from '@capacitor/browser';

@Injectable({
  providedIn: 'root',
})
export class MainService {
  private router = inject(Router);
  private searchService = inject(SearchService);
  private searchPageService = inject(SearchPageService);
  private firebaseService = inject(FirebaseService);
  private loadingCtrl = inject(LoadingController);
  private navCtrl = inject(NavController);

  homeTab = new Subject();
  searchTab = new Subject();

  registerTab = new Subject();

  negotiationsTab = new Subject();
  profileTab = new Subject();

  // tab stack workaround
  redirectRegister = false;

  productRoutes = ['home', 'search', 'negotiations', 'profile'];

  getRoute() {
    for (const i of this.productRoutes) {
      if (this.router.url.includes(i)) return i;
    }
  }

  navigateToProduct(productId) {
    this.navCtrl.navigateForward(
      `/main/${this.getRoute()}/product/${productId}`,
    );
  }

  navigateToQuestion(productId, questionId?) {
    const base = `/main/${this.getRoute()}/product/${productId}/question`;
    this.navCtrl.navigateForward(questionId ? `${base}/${questionId}` : base);
  }

  navigateToWardrobe(userId) {
    this.navCtrl.navigateForward(
      `/main/${this.getRoute()}/wardrobe/${userId}/${new Date().getTime()}`,
    );
  }

  navigateToCarts(ownerId?) {
    this.navCtrl.navigateForward(`/main/${this.getRoute() ?? 'home'}/carts`);
  }

  navigateToCheckout() {
    this.router.navigateByUrl('/buying/checkout');
  }

  openTrokaiWebsite(url: string) {
    const urlObj = new URL(url);
    urlObj.searchParams.set('utm_source', 'app');
    Browser.open({ url: urlObj.href });
  }

  openTrokaiWebsitePath(path: string) {
    const urlObj = new URL(path, 'https://www.trokai.com.br');
    urlObj.searchParams.set('utm_source', 'app');
    Browser.open({ url: urlObj.href });
  }

  async processLink(urlObj: URL, fallbackUrl?: string) {
    const loading = await this.loadingCtrl.create({ message: 'Buscando' });
    loading.present();

    const pathName = urlObj.pathname.split('/');

    try {
      switch (pathName[1].trim()) {
        case 'items': {
          const explode = pathName[2].split('-');
          const id = explode[explode.length - 1];
          this.navigateToProduct(id);
          loading.dismiss();
          break;
        }

        case 'users': {
          const nick = pathName[2];
          const user = await this.searchService.getUserInfo(nick);
          this.navigateToWardrobe(user._id);
          loading.dismiss();
          break;
        }

        case 'search': {
          const filters = {};

          urlObj.searchParams.forEach((value, key) => {
            const _value = !isNaN(Number(value)) ? Number(value) : value;
            if (filters[key] && !(filters[key] instanceof Array))
              filters[key] = [filters[key], _value];
            else if (filters[key] && filters[key] instanceof Array)
              filters[key].push(_value);
            else filters[key] = _value;
          });

          setTimeout(() => {
            this.searchPageService.reset();
            this.searchPageService.homeSearch = true;
            this.searchPageService.setFilters(filters as any);
            this.router.navigate(['/main/search']);
            loading.dismiss();
          }, 500);

          break;
        }

        case '': {
          // do nothing
          loading.dismiss();
          break;
        }

        default: {
          this.openTrokaiWebsite(fallbackUrl ?? urlObj.href);
          loading.dismiss();

          break;
        }
      }
    } catch (err) {
      this.firebaseService.log('DEEP_LINK_ERRO');
      console.error('Error processing link', err);
      loading.dismiss();
    }
  }
}

import { inject, Injectable } from '@angular/core';
import {
  Camera,
  CameraResultType,
  CameraSource,
  GalleryPhoto,
} from '@capacitor/camera';
import { Capacitor } from '@capacitor/core';
import { Filesystem } from '@capacitor/filesystem';
import { ModalController } from '@ionic/angular/standalone';
import { MediaService, MediaCapabilities } from '@trokai/shared-core';
import { CameraPreviewComponent } from '../shared/components/camera-preview/camera-preview.component';

/**
 * Mobile media impl: Capacitor camera + native gallery. The shared image-resize pipeline
 * (resizeBlob/resizeBase64/processFile) is inherited from the base `MediaService`.
 * Provided as `{ provide: MediaService, useClass: MobileMediaService }` in main.ts.
 */
@Injectable()
export class MobileMediaService extends MediaService {
  private modalCtrl = inject(ModalController);

  readonly capabilities: MediaCapabilities = {
    camera: Capacitor.isPluginAvailable('Camera'),
    nativeGallery: Capacitor.isPluginAvailable('Camera'),
  };

  /** Read a Capacitor GalleryPhoto, resize it, and return a JPEG Blob. */
  private async processGalleryPhoto(photo: GalleryPhoto): Promise<Blob | null> {
    try {
      // webPath is Capacitor's local-server URL — fetch() works on iOS & Android
      // without a base64 round-trip. Fall back to Filesystem only when unavailable.
      if (photo.webPath) {
        const response = await fetch(photo.webPath);
        const blob = await response.blob();
        return this.resizeBlob(blob);
      }
      const contents = await Filesystem.readFile({ path: photo.path! });
      return this.resizeBase64('data:image/jpeg;base64,' + contents.data);
    } catch {
      return null;
    }
  }

  /** Open the custom camera preview modal and return the resized JPEG Blob (or null). */
  async openCameraPreview(): Promise<Blob | null> {
    const modal = await this.modalCtrl.create({
      component: CameraPreviewComponent,
    });
    await modal.present();
    const { data } = await modal.onDidDismiss();
    if (!data?.image) return null;
    return this.resizeBase64(data.image);
  }

  /** Pick a single photo from the device gallery and return the resized JPEG Blob (or null). */
  async pickSingleFromGallery(): Promise<Blob | null> {
    try {
      const permissions = await Camera.checkPermissions();
      if (permissions.photos !== 'granted') {
        await Camera.requestPermissions({ permissions: ['photos'] });
      }
      const photo = await Camera.getPhoto({
        source: CameraSource.Photos,
        resultType: CameraResultType.Uri,
        quality: 90,
      });
      if (!photo?.webPath) return null;
      const response = await fetch(photo.webPath);
      const blob = await response.blob();
      return this.resizeBlob(blob);
    } catch {
      return null;
    }
  }

  /** Pick up to `limit` photos from the gallery and return resized JPEG Blobs. */
  async pickMultipleFromGallery(limit: number): Promise<Blob[]> {
    try {
      const permissions = await Camera.checkPermissions();
      if (permissions.photos !== 'granted') {
        await Camera.requestPermissions({ permissions: ['photos'] });
      }
      const result = await Camera.pickImages({ quality: 90, limit });
      if (!result?.photos?.length) return [];
      const blobs = await Promise.all(
        result.photos.map((p) => this.processGalleryPhoto(p))
      );
      return blobs.filter(Boolean) as Blob[];
    } catch {
      return [];
    }
  }
}

import { inject, Injectable } from '@angular/core';
import { AuthService } from './auth.service';
import { take, tap } from 'rxjs/operators';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { environment } from 'src/environments/environment';
import { AuthResponseData } from '@trokai/shared-core';

@Injectable({
  providedIn: 'root',
})
export class PasswordServiceService {
  private authService = inject(AuthService);
  private httpClient = inject(HttpClient);

  emailToCode = null; // email para enviar o codigo de alterar a senha
  code = null;
  validatingUser = null;

  changePassword(currentPassword, newPassword) {
    let token;
    this.authService.user.pipe(take(1)).subscribe((u) => (token = u.token));

    // tslint:disable-next-line: object-literal-shorthand
    return this.httpClient.post(
      environment.urlApi + '/users/new-password',
      { currentPassword: currentPassword, newPassword: newPassword },
      {
        headers: new HttpHeaders({
          Authorization: token,
        }),
      },
    );
  }

  changePasswordForgot(newPassword) {
    return this.httpClient
      .post(environment.urlApi + '/users/change-password-forgot', {
        email: this.emailToCode,
        code: this.code,
        newPassword: newPassword,
      })
      .pipe(
        tap((r) => {
          this.emailToCode = null;
          this.code = null;
        }),
      );
  }

  sendForgotCode(email: string) {
    return this.httpClient.post(environment.urlApi + '/users/forgot-password', {
      email: email,
    });
  }

  verifyCode(code: string, email: string) {
    return this.httpClient
      .post<AuthResponseData>(
        environment.urlApi + '/users/verify-email-password-code',
        {
          email: email,
          code: code,
        },
      )
      .pipe(
        tap((r) => {
          this.emailToCode = email;
          this.code = code;
          this.validatingUser = r.user;
        }),
      );
  }
}

import { HttpClient } from '@angular/common/http';
import { inject, Injectable } from '@angular/core';
import { BehaviorSubject, lastValueFrom, Subject } from 'rxjs';
import { environment } from 'src/environments/environment';
import {
  ActionPerformed,
  PushNotifications,
  PushNotificationSchema,
  Token,
} from '@capacitor/push-notifications';
import { LocalNotifications } from '@capacitor/local-notifications';

@Injectable({
  providedIn: 'root',
})
export class PushNotificationsService {
  private http = inject(HttpClient);

  private firebaseToken;
  private associated = false;
  private _registered = new BehaviorSubject<boolean>(false); // has firebaseToken

  public pushReceived$ = new Subject<PushNotificationSchema>();
  public pushAction$ = new Subject<ActionPerformed>();
  public registered$ = this._registered.asObservable();

  public isRegistered() {
    return this._registered.getValue();
  }

  // use on app start
  private setLocalToken(firebaseToken: string) {
    this.firebaseToken = firebaseToken;
    this._registered.next(true);
  }

  // use after login
  public async userAssociate() {
    if (!this.firebaseToken || this.associated) return;
    this.associated = true;

    await lastValueFrom(
      this.http.post(environment.urlApi + '/users/device-token', {
        token: this.firebaseToken,
      }),
    );
  }

  // use after logout
  public async userDissociate() {
    if (!this.firebaseToken || !this.associated) return;

    await lastValueFrom(
      this.http.delete<any>(
        `${environment.urlApi}/users/device-token/${this.firebaseToken}`,
      ),
    );

    this.associated = false;
  }

  async showLocal(notification) {
    await LocalNotifications.schedule({
      notifications: [
        {
          title: notification.title,
          body: notification.body,
          id: 1,
          schedule: { at: new Date(Date.now() + 1000) },
          sound: null,
          attachments: null,
          actionTypeId: '',
          extra: null,
        },
      ],
    });
  }

  // use on app start
  public async start() {
    // add listeners
    await PushNotifications.addListener('registration', (token: Token) => {
      this.setLocalToken(token.value);
    });

    await PushNotifications.addListener('registrationError', (error: any) =>
      console.log('push registration error', JSON.stringify(error)),
    );

    await PushNotifications.addListener(
      'pushNotificationReceived',
      (notification: PushNotificationSchema) => {
        this.pushReceived$.next(notification);
        this.showLocal(notification);
      },
    );

    await PushNotifications.addListener(
      'pushNotificationActionPerformed',
      (notification: ActionPerformed) => this.pushAction$.next(notification),
    );

    // register device
    await this.firebaseRegister();
  }

  private async permissions(): Promise<boolean> {
    let permStatus = await PushNotifications.checkPermissions();

    if (permStatus.receive === 'prompt')
      permStatus = await PushNotifications.requestPermissions();

    return permStatus.receive === 'granted';
  }

  private async firebaseRegister() {
    const perm = await this.permissions();
    if (!perm || this.firebaseToken) return;

    await PushNotifications.register();
  }
}

